code = """import json
import re

# Load UC patents data
uc_data = locals()['var_functions.query_db:78']

# Debug: Let's see what the first few records look like
print('First record structure:')
print(type(uc_data[0]))
print(uc_data[0])

# More comprehensive extraction - search for any pattern that looks like a publication number
uc_pub_numbers = set()
for item in uc_data:
    if isinstance(item, dict):
        info = item.get('Patents_info', '')
        # Find all patterns that match patent publication format: XX-Y..Y-ZZZZ
        matches = re.findall(r'\b([A-Z]{2}-[A-Z0-9]{3,}-[A-Z0-9]+)\b', info)
        if matches:
            for match in matches:
                # Skip application numbers (they don't have kind codes like -A1, -B2, etc.)
                if any(kind in match[-4:] for kind in ['-A1', '-A', '-B1', '-B2', '-B']):
                    uc_pub_numbers.add(match)

print('\nExtracted UC publication numbers:', len(uc_pub_numbers))
print('Sample:', sorted(list(uc_pub_numbers))[:20])

result = {'uc_pub_numbers_count': len(uc_pub_numbers), 'sample': sorted(list(uc_pub_numbers))[:20]}
print('__RESULT__:')
print(json.dumps(result))"""

